#include<iostream>#include<vector>#include<algorithm>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        int n;        cin>>n;        vector<int> a(n);        for(int i=0;i<n;i++){            cin>>a[i];        }        vector<int>b(n);        for(int i=0;i<n;i++){            cin>>b[i];        }        int changed_i=-1;        int changed_j=-1;        for(int i=0;i<n;i++){            if(a[i]!=b[i]){                if(changed_i==-1){                    changed_i=i;                }                else{                    changed_j=i;                    break;                }                            }        }                if(changed_j==-1){            changed_j = n-1;        }        int i= changed_i-1;        int j= changed_j+1;        while(i>=0){            if(b[i]<=b[i+1]){                i--;            }            else{                break;            }        }        changed_i=i+1;        while(j<n){            if(b[j]>=b[j-1]){                j++;            }            else{                break;            }        }        changed_j=j-1;        cout<<changed_i+1<<" "<<changed_j + 1<<"\n";    }}